// Нормализация входа Telegram: текст или фото-доказательство.
// Валидация: фото считается принятым, если Telegram прислал file_size > 0
// (файл уже принят на серверы Telegram). Реальное скачивание байтов — позже, для Vision.
const msg = $input.first().json.message || {};
const chatId = msg.chat && msg.chat.id;
let normalized_text = '';
let evidence = { has_photo: false, file_id: null, file_size: 0, downloaded: false };

if (Array.isArray(msg.photo) && msg.photo.length) {
  const p = msg.photo[msg.photo.length - 1]; // последний = наибольшее разрешение
  const size = p.file_size || 0;
  evidence = { has_photo: true, file_id: p.file_id, file_size: size, downloaded: size > 0 };
  if (size > 0) {
    const cap = msg.caption ? ` Подпись: ${msg.caption}` : '';
    normalized_text = `[Доказательство-фото получено и принято, file_id=${p.file_id}, размер ${size} байт — OK.${cap}]`;
  } else {
    normalized_text = '[Фото НЕ удалось принять — попроси прислать заново или описать доказательство текстом]';
  }
} else if (msg.text) {
  normalized_text = msg.text;
} else if (msg.caption) {
  normalized_text = msg.caption;
} else {
  normalized_text = '[Получено сообщение без текста — попроси повторить текстом]';
}

return [{ json: { chat_id: chatId, normalized_text, evidence, _raw: msg } }];

// query — строка от агента, напр.: "violationDate=2026-01-15; discoveryDate=2026-01-20"
// Сроки — внутренний буфер Контура (НЕ дословно ТК РФ):
//   нарушение: +5 мес 15 дн;  обнаружение: +20 дн.
// ТК РФ baseline: 6 мес / 30 дн. Уточнять у Касмыниной О.
const text = String(query || '');
const dates = text.match(/\d{4}-\d{2}-\d{2}/g) || [];
const violationStr = dates[0];
const discoveryStr = dates[1] || dates[0];
if (!violationStr) {
  return JSON.stringify({ error: 'Не нашёл дат в формате ГГГГ-ММ-ДД', received: text });
}
const now = new Date();
const violationDate = new Date(violationStr);
const discoveryDate = new Date(discoveryStr);
const vDeadline = new Date(violationDate);
vDeadline.setMonth(vDeadline.getMonth() + 5);
vDeadline.setDate(vDeadline.getDate() + 15);
const dDeadline = new Date(discoveryDate);
dDeadline.setDate(dDeadline.getDate() + 20);
const expiredByViolation = now >= vDeadline;
const expiredByDiscovery = now >= dDeadline;
const fmt = (d) => d.toISOString().split('T')[0];
return JSON.stringify({
  isExpired: expiredByViolation || expiredByDiscovery,
  expiredReason: expiredByViolation ? 'violation_date' : (expiredByDiscovery ? 'discovery_date' : null),
  violationDeadline: fmt(vDeadline),
  discoveryDeadline: fmt(dDeadline),
  today: fmt(now)
});

// Формат ответа агента для Telegram (HTML) + разбивка на части ≤4096
const chatId = $('Telegram: входящие').item.json.message.chat.id;
let t = String($json.output ?? '');

// 1) экранируем HTML-спецсимволы (ДО вставки тегов)
t = t.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

// 2) markdown → HTML
t = t.replace(/\*\*(.+?)\*\*/g, '<b>$1</b>');     // **жирный** → <b>
t = t.replace(/^#{1,6}\s*(.+)$/gm, '<b>$1</b>');  // ## Заголовок → жирный

// 3) режем на части ≤4000 по границам строк (теги <b> внутри строки не рвутся)
const LIMIT = 4000;
const parts = [];
let buf = '';
for (const line of t.split('\n')) {
  if (buf.length + line.length + 1 > LIMIT) {
    if (buf) parts.push(buf);
    buf = line;
    while (buf.length > LIMIT) { parts.push(buf.slice(0, LIMIT)); buf = buf.slice(LIMIT); }
  } else {
    buf = buf ? buf + '\n' + line : line;
  }
}
if (buf) parts.push(buf);

// несколько items → Telegram-нода (per item) отправит каждую часть отдельным сообщением
return parts.map(p => ({ json: { chat_id: chatId, text: p } }));
